-- 베리타 상점: item_teleport uid 1~89 전부 판매, 단가 2만 아데나, 그래픽은 오만 1층 이동 주문서와 동일(인벤ID 5487, GFXID 22).
-- 적용: 서버·GM과 동일한 DB(보통 MariaDB, 싱글 팩 mysql.conf 의 DB)에 실행.
--       예: mariadb/mysql CLI, HeidiSQL, DBeaver 등에서 이 파일 내용 실행.
-- 주의: item PK는 아이템이름. REPLACE INTO 로 동명 아이템을 이 템플릿으로 덮어씁니다.

SET NAMES utf8mb4;

DELETE FROM `npc_shop` WHERE `name` = '베리타';

-- item 정의 (구분2 = teleport_<item_teleport.uid>)

